{
  "name": "EvoFit AI",
  "description": "Seu Personal Trainer inteligente e evolutivo. Planos de treino personalizados, chat com IA e acompanhamento de progresso."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserGoal {
  WeightLoss = 'Emagrecimento',
  MuscleGain = 'Ganho de massa',
  Definition = 'Definição',
  Conditioning = 'Condicionamento',
}

export enum UserLevel {
  Beginner = 'Iniciante',
  Intermediate = 'Intermediário',
  Advanced = 'Avançado',
}

export enum TrainingLocation {
  Gym = 'Academia',
  Home = 'Casa',
}

export enum Gender {
  Male = 'Masculino',
  Female = 'Feminino',
}

export interface UserProfile {
  name: string;
  email: string;
  age: number;
  weight: number;
  height: number;
  gender: Gender;
  goal: UserGoal;
  level: UserLevel;
  location: TrainingLocation;
  isPremium: boolean;
  freeQuestionsCount: number; // Reset daily logic mocked
  joinedDate: string;
}

export interface Exercise {
  name: string;
  sets: number;
  reps: string;
  notes?: string;
}

export interface DailyWorkout {
  day: string;
  focus: string;
  exercises: Exercise[];
}

export interface WorkoutPlan {
  weeklySummary: string;
  schedule: DailyWorkout[];
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserProfile, WorkoutPlan, ChatMessage } from "../types";

const apiKey = process.env.API_KEY || '';

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey });

// System instruction base for the persona
const PERSONAL_TRAINER_SYSTEM_INSTRUCTION = `
Você é um Personal Trainer profissional (EvoFit AI) especializado em emagrecimento, hipertrofia e saúde geral.
Características:
- Profissional, motivador e claro.
- Especialista em adaptar treinos para casa ou academia.
- Fornece dicas de alimentação saudável (sem prescrever dietas médicas restritivas).
- Incentiva disciplina e constância.
- Nunca forneça recomendações médicas para tratamento de lesões graves.
`;

export const generateWorkoutPlan = async (user: UserProfile): Promise<WorkoutPlan> => {
  const modelId = "gemini-3-flash-preview";

  const prompt = `
    Crie um plano semanal de treino estruturado para o seguinte aluno:
    Nome: ${user.name}
    Idade: ${user.age}
    Peso: ${user.weight}kg
    Altura: ${user.height}cm
    Sexo: ${user.gender}
    Objetivo: ${user.goal}
    Local de Treino: ${user.location}
    Nível: ${user.level}

    O plano deve ser detalhado, dividido por dias da semana.
  `;

  const exerciseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      name: { type: Type.STRING },
      sets: { type: Type.INTEGER },
      reps: { type: Type.STRING },
      notes: { type: Type.STRING },
    },
    required: ["name", "sets", "reps"],
  };

  const daySchema: Schema = {
    type: Type.OBJECT,
    properties: {
      day: { type: Type.STRING, description: "Dia da semana (ex: Segunda-feira)" },
      focus: { type: Type.STRING, description: "Foco do treino (ex: Peito e Tríceps)" },
      exercises: {
        type: Type.ARRAY,
        items: exerciseSchema,
      },
    },
    required: ["day", "focus", "exercises"],
  };

  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      weeklySummary: { type: Type.STRING, description: "Resumo motivacional da semana" },
      schedule: {
        type: Type.ARRAY,
        items: daySchema,
      },
    },
    required: ["weeklySummary", "schedule"],
  };

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: PERSONAL_TRAINER_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as WorkoutPlan;
  } catch (error) {
    console.error("Error generating workout:", error);
    throw error;
  }
};

export const chatWithTrainer = async (
  history: ChatMessage[], 
  newMessage: string, 
  user: UserProfile
): Promise<string> => {
  const modelId = "gemini-3-flash-preview";

  // Context injection
  const contextPrompt = `
  Contexto do aluno atual:
  Nome: ${user.name}, Objetivo: ${user.goal}, Nível: ${user.level}, Local: ${user.location}.
  `;

  // Construct history for the API
  // Note: Simple history construction for stateless request, ideally utilize ai.chats.create for stateful session
  // But strictly following guidelines to use generateContent or chat.sendMessage.

  const chat = ai.chats.create({
    model: modelId,
    config: {
      systemInstruction: PERSONAL_TRAINER_SYSTEM_INSTRUCTION + contextPrompt,
    }
  });

  // Replay history (simplified for this demo, in prod use history prop of chats.create)
  // We will just send the new message effectively as the "history" is managed by the UI state mostly,
  // but for better context, we should ideally pass previous turns. 
  // For this demo, we assume the system instruction + user context is enough for a stateless-feeling 'smart' reply
  // or we could iterate history to add to chat.

  for (const msg of history) {
    if (msg.role === 'user') {
      await chat.sendMessage({ message: msg.text });
    } 
    // We can't easily force insert model replies into the history object of the SDK directly 
    // without using the specific history init option. 
    // To keep it simple and robust:
  }

  const response = await chat.sendMessage({ message: newMessage });
  return response.text || "Desculpe, não consegui processar sua resposta. Tente novamente.";
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { UserProfile, WorkoutPlan, ChatMessage } from '../types';

interface AppContextType {
  user: UserProfile | null;
  setUser: (user: UserProfile | null) => void;
  workoutPlan: WorkoutPlan | null;
  setWorkoutPlan: (plan: WorkoutPlan | null) => void;
  chatHistory: ChatMessage[];
  addChatMessage: (message: ChatMessage) => void;
  isLoading: boolean;
  setIsLoading: (loading: boolean) => void;
  logout: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [workoutPlan, setWorkoutPlan] = useState<WorkoutPlan | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Persist user to local storage for demo purposes
  useEffect(() => {
    const storedUser = localStorage.getItem('evofit_user');
    const storedPlan = localStorage.getItem('evofit_plan');
    if (storedUser) setUser(JSON.parse(storedUser));
    if (storedPlan) setWorkoutPlan(JSON.parse(storedPlan));
  }, []);

  useEffect(() => {
    if (user) localStorage.setItem('evofit_user', JSON.stringify(user));
    else localStorage.removeItem('evofit_user');
  }, [user]);

  useEffect(() => {
    if (workoutPlan) localStorage.setItem('evofit_plan', JSON.stringify(workoutPlan));
    else localStorage.removeItem('evofit_plan');
  }, [workoutPlan]);

  const addChatMessage = (message: ChatMessage) => {
    setChatHistory((prev) => [...prev, message]);
  };

  const logout = () => {
    setUser(null);
    setWorkoutPlan(null);
    setChatHistory([]);
    localStorage.clear();
  };

  return (
    <AppContext.Provider value={{
      user,
      setUser,
      workoutPlan,
      setWorkoutPlan,
      chatHistory,
      addChatMessage,
      isLoading,
      setIsLoading,
      logout
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React from 'react';
import { useApp } from '../context/AppContext';
import { Dumbbell, MessageSquare, User, Crown, LogOut, LayoutDashboard } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { user, logout } = useApp();

  if (!user) return <>{children}</>;

  const navItems = [
    { id: 'dashboard', icon: LayoutDashboard, label: 'Início' },
    { id: 'workout', icon: Dumbbell, label: 'Treino' },
    { id: 'chat', icon: MessageSquare, label: 'IA Personal' },
    { id: 'profile', icon: User, label: 'Perfil' },
  ];

  return (
    <div className="min-h-screen bg-dark-bg text-dark-text flex flex-col max-w-md mx-auto shadow-xl overflow-hidden relative">
      {/* Header */}
      <header className="p-4 bg-dark-card border-b border-gray-800 flex justify-between items-center sticky top-0 z-10">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center">
            <Dumbbell className="text-white w-5 h-5" />
          </div>
          <h1 className="font-bold text-xl tracking-tight">EvoFit<span className="text-brand-500">AI</span></h1>
        </div>
        {!user.isPremium && (
            <button onClick={() => setActiveTab('premium')} className="text-xs bg-yellow-500/10 text-yellow-500 px-3 py-1 rounded-full border border-yellow-500/50 flex items-center gap-1 animate-pulse">
                <Crown size={12} />
                Premium
            </button>
        )}
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-20 scrollbar-hide">
        {children}
      </main>

      {/* Bottom Navigation */}
      <nav className="bg-dark-card border-t border-gray-800 absolute bottom-0 w-full z-20">
        <div className="flex justify-around items-center h-16">
          {navItems.map((item) => {
            const Icon = item.icon;
            const isActive = activeTab === item.id;
            return (
              <button
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`flex flex-col items-center justify-center w-full h-full space-y-1 transition-colors ${
                  isActive ? 'text-brand-500' : 'text-gray-500 hover:text-gray-300'
                }`}
              >
                <Icon size={20} />
                <span className="text-[10px] font-medium">{item.label}</span>
              </button>
            );
          })}
        </div>
      </nav>
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { UserProfile, UserGoal, UserLevel, TrainingLocation, Gender } from '../types';
import { ArrowRight, ArrowLeft, Ruler, Weight, User as UserIcon } from 'lucide-react';
import { generateWorkoutPlan } from '../services/geminiService';

interface OnboardingProps {
  onComplete: () => void;
}

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const { setUser, setWorkoutPlan, setIsLoading } = useApp();
  const [step, setStep] = useState(1);
  const totalSteps = 4;

  const [formData, setFormData] = useState<Partial<UserProfile>>({
    name: '',
    email: '',
    age: 25,
    weight: 70,
    height: 170,
    gender: Gender.Male,
    goal: UserGoal.MuscleGain,
    level: UserLevel.Beginner,
    location: TrainingLocation.Gym,
    isPremium: false,
    freeQuestionsCount: 0,
    joinedDate: new Date().toISOString()
  });

  const handleChange = (field: keyof UserProfile, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleNext = async () => {
    if (step < totalSteps) {
      setStep(prev => prev + 1);
    } else {
      // Finish
      setIsLoading(true);
      try {
        const fullProfile = formData as UserProfile;
        setUser(fullProfile);

        // Generate initial plan
        const plan = await generateWorkoutPlan(fullProfile);
        setWorkoutPlan(plan);

        onComplete();
      } catch (error) {
        alert("Erro ao gerar treino inicial. Tente novamente.");
        console.error(error);
      } finally {
        setIsLoading(false);
      }
    }
  };

  const handleBack = () => {
    if (step > 1) setStep(prev => prev - 1);
  };

  return (
    <div className="h-screen bg-dark-bg text-white p-6 flex flex-col max-w-md mx-auto">
      {/* Progress Bar */}
      <div className="mb-8 mt-4">
        <div className="flex justify-between text-xs text-dark-muted mb-2">
          <span>Passo {step} de {totalSteps}</span>
          <span>{Math.round((step / totalSteps) * 100)}%</span>
        </div>
        <div className="h-2 bg-dark-card rounded-full overflow-hidden">
          <div 
            className="h-full bg-brand-500 transition-all duration-300"
            style={{ width: `${(step / totalSteps) * 100}%` }}
          ></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto">
        {step === 1 && (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-2xl font-bold">Vamos criar seu perfil</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm text-dark-muted mb-1">Nome</label>
                <input 
                  type="text" 
                  value={formData.name}
                  onChange={(e) => handleChange('name', e.target.value)}
                  className="w-full bg-dark-card border border-gray-700 rounded-lg p-3 text-white focus:border-brand-500 focus:outline-none"
                  placeholder="Seu nome"
                />
              </div>
              <div>
                <label className="block text-sm text-dark-muted mb-1">Email</label>
                <input 
                  type="email" 
                  value={formData.email}
                  onChange={(e) => handleChange('email', e.target.value)}
                  className="w-full bg-dark-card border border-gray-700 rounded-lg p-3 text-white focus:border-brand-500 focus:outline-none"
                  placeholder="seu@email.com"
                />
              </div>
              <div>
                <label className="block text-sm text-dark-muted mb-1">Sexo Biológico</label>
                <div className="grid grid-cols-2 gap-3">
                  {Object.values(Gender).map((g) => (
                    <button
                      key={g}
                      onClick={() => handleChange('gender', g)}
                      className={`p-3 rounded-lg border ${formData.gender === g ? 'bg-brand-500/20 border-brand-500 text-brand-500' : 'bg-dark-card border-gray-700 text-gray-400'}`}
                    >
                      {g}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-2xl font-bold">Suas medidas</h2>
            <div className="space-y-6">
              <div>
                <label className="block text-sm text-dark-muted mb-1">Idade</label>
                <div className="flex items-center bg-dark-card border border-gray-700 rounded-lg px-3">
                  <UserIcon size={20} className="text-gray-500" />
                  <input 
                    type="number" 
                    value={formData.age}
                    onChange={(e) => handleChange('age', Number(e.target.value))}
                    className="w-full bg-transparent p-3 text-white focus:outline-none"
                  />
                  <span className="text-gray-500 text-sm">anos</span>
                </div>
              </div>
              <div>
                <label className="block text-sm text-dark-muted mb-1">Peso</label>
                <div className="flex items-center bg-dark-card border border-gray-700 rounded-lg px-3">
                  <Weight size={20} className="text-gray-500" />
                  <input 
                    type="number" 
                    value={formData.weight}
                    onChange={(e) => handleChange('weight', Number(e.target.value))}
                    className="w-full bg-transparent p-3 text-white focus:outline-none"
                  />
                  <span className="text-gray-500 text-sm">kg</span>
                </div>
              </div>
              <div>
                <label className="block text-sm text-dark-muted mb-1">Altura</label>
                <div className="flex items-center bg-dark-card border border-gray-700 rounded-lg px-3">
                  <Ruler size={20} className="text-gray-500" />
                  <input 
                    type="number" 
                    value={formData.height}
                    onChange={(e) => handleChange('height', Number(e.target.value))}
                    className="w-full bg-transparent p-3 text-white focus:outline-none"
                  />
                  <span className="text-gray-500 text-sm">cm</span>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-2xl font-bold">Seu Objetivo</h2>
            <div className="grid grid-cols-1 gap-3">
              {Object.values(UserGoal).map((goal) => (
                <button
                  key={goal}
                  onClick={() => handleChange('goal', goal)}
                  className={`p-4 rounded-xl border text-left transition-all ${
                    formData.goal === goal 
                    ? 'bg-brand-500/20 border-brand-500 text-white' 
                    : 'bg-dark-card border-gray-700 text-gray-400 hover:border-gray-500'
                  }`}
                >
                  <span className="font-semibold block">{goal}</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-2xl font-bold">Experiência e Local</h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm text-dark-muted mb-2">Nível de Experiência</label>
                <div className="grid grid-cols-1 gap-2">
                  {Object.values(UserLevel).map((lvl) => (
                    <button
                      key={lvl}
                      onClick={() => handleChange('level', lvl)}
                      className={`p-3 rounded-lg border text-sm ${formData.level === lvl ? 'bg-brand-500/20 border-brand-500 text-brand-500' : 'bg-dark-card border-gray-700 text-gray-400'}`}
                    >
                      {lvl}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm text-dark-muted mb-2">Onde você treina?</label>
                <div className="grid grid-cols-2 gap-3">
                  {Object.values(TrainingLocation).map((loc) => (
                    <button
                      key={loc}
                      onClick={() => handleChange('location', loc)}
                      className={`p-3 rounded-lg border text-sm ${formData.location === loc ? 'bg-brand-500/20 border-brand-500 text-brand-500' : 'bg-dark-card border-gray-700 text-gray-400'}`}
                    >
                      {loc}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="mt-6 flex gap-3">
        {step > 1 && (
          <button 
            onClick={handleBack}
            className="px-6 py-4 rounded-xl bg-dark-card text-white font-bold border border-gray-700"
          >
            <ArrowLeft />
          </button>
        )}
        <button 
          onClick={handleNext}
          disabled={step === 1 && !formData.name}
          className="flex-1 bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-2 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {step === totalSteps ? 'Gerar Treino IA' : 'Próximo'} 
          {step !== totalSteps && <ArrowRight size={20} />}
        </button>
      </div>
    </div>
  );
};

export default Onboarding;

import React from 'react';
import { useApp } from '../context/AppContext';
import { Activity, Flame, TrendingUp, Calendar } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const Dashboard: React.FC = () => {
  const { user, workoutPlan } = useApp();

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Bom dia';
    if (hour < 18) return 'Boa tarde';
    return 'Boa noite';
  };

  const today = new Date().toLocaleDateString('pt-BR', { weekday: 'long' });
  // Simple logic to find today's workout based on Portuguese day names or fallback to first
  const todayWorkout = workoutPlan?.schedule.find(d => d.day.toLowerCase().includes(today.split('-')[0].toLowerCase())) || workoutPlan?.schedule[0];

  // Mock data for the chart
  const data = [
    { name: 'Seg', cal: 320 },
    { name: 'Ter', cal: 450 },
    { name: 'Qua', cal: 280 },
    { name: 'Qui', cal: 500 },
    { name: 'Sex', cal: 380 },
    { name: 'Sab', cal: 600 },
    { name: 'Dom', cal: 0 },
  ];

  return (
    <div className="p-4 space-y-6 animate-fadeIn">
      {/* Welcome Header */}
      <div>
        <h2 className="text-dark-muted text-sm">{getGreeting()},</h2>
        <h1 className="text-2xl font-bold text-white">{user?.name}</h1>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 gap-3">
        <div className="bg-dark-card p-4 rounded-xl border border-gray-800">
          <div className="flex items-center gap-2 text-orange-500 mb-2">
            <Flame size={18} />
            <span className="text-xs font-bold">Sequência</span>
          </div>
          <p className="text-2xl font-bold text-white">3 <span className="text-sm font-normal text-gray-500">dias</span></p>
        </div>
        <div className="bg-dark-card p-4 rounded-xl border border-gray-800">
          <div className="flex items-center gap-2 text-brand-500 mb-2">
            <Activity size={18} />
            <span className="text-xs font-bold">Treinos</span>
          </div>
          <p className="text-2xl font-bold text-white">12 <span className="text-sm font-normal text-gray-500">total</span></p>
        </div>
      </div>

      {/* Today's Workout Card */}
      <div className="bg-gradient-to-br from-brand-900 to-brand-950 p-5 rounded-2xl border border-brand-800 relative overflow-hidden">
        <div className="absolute right-0 top-0 p-4 opacity-10">
            <Calendar size={60} />
        </div>
        <div className="relative z-10">
            <div className="flex justify-between items-start mb-4">
                <div>
                    <h3 className="text-brand-200 text-sm font-medium uppercase tracking-wider">Treino de Hoje</h3>
                    <p className="text-white font-bold text-lg mt-1 capitalize">{todayWorkout?.focus || "Descanso"}</p>
                </div>
                <span className="bg-brand-500/20 text-brand-300 text-xs px-2 py-1 rounded capitalize">{todayWorkout?.day}</span>
            </div>

            <div className="space-y-2 mb-4">
                {todayWorkout?.exercises.slice(0, 3).map((ex, idx) => (
                    <div key={idx} className="flex justify-between text-sm text-brand-100/80 border-b border-brand-800/50 pb-1 last:border-0">
                        <span>{ex.name}</span>
                        <span>{ex.sets}x{ex.reps}</span>
                    </div>
                ))}
                {todayWorkout && todayWorkout.exercises.length > 3 && (
                    <p className="text-xs text-brand-400 mt-1 italic">+ {todayWorkout.exercises.length - 3} outros exercícios</p>
                )}
            </div>

            <button className="w-full bg-white text-brand-900 font-bold py-2 rounded-lg text-sm hover:bg-gray-100 transition-colors">
                Iniciar Treino
            </button>
        </div>
      </div>

      {/* Weekly Progress Chart */}
      <div className="bg-dark-card p-4 rounded-xl border border-gray-800">
        <div className="flex items-center justify-between mb-4">
            <h3 className="font-bold text-white flex items-center gap-2">
                <TrendingUp size={16} className="text-brand-500"/>
                Atividade Semanal
            </h3>
        </div>
        <div className="h-48 w-full">
            <ResponsiveContainer width="100%" height="100%">
                <BarChart data={data}>
                    <XAxis dataKey="name" tick={{fontSize: 10, fill: '#64748b'}} axisLine={false} tickLine={false} />
