import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { chatWithTrainer } from '../services/geminiService';
import { Send, Bot, User, Loader2, Lock } from 'lucide-react';
import { ChatMessage } from '../types';

interface AIChatProps {
    onOpenPremium: () => void;
}

const AIChat: React.FC<AIChatProps> = ({ onOpenPremium }) => {
  const { user, chatHistory, addChatMessage } = useApp();
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Free tier limit logic
  const MAX_FREE_QUESTIONS = 3;
  // Count user messages in history that happened "today" (simplified for demo to just total history length for session)
  const userMsgCount = chatHistory.filter(m => m.role === 'user').length;
  const isLimitReached = !user?.isPremium && userMsgCount >= MAX_FREE_QUESTIONS;

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatHistory, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || !user) return;
    if (isLimitReached) {
        onOpenPremium();
        return;
    }

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    addChatMessage(userMsg);
    setInput('');
    setIsTyping(true);

    try {
      const responseText = await chatWithTrainer(chatHistory, input, user);

      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      addChatMessage(botMsg);
    } catch (error) {
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Desculpe, estou tendo problemas para conectar. Tente novamente mais tarde.",
        timestamp: Date.now()
      };
      addChatMessage(errorMsg);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-dark-bg">
      <div className="p-4 bg-dark-card border-b border-gray-800 shadow-sm">
        <h2 className="text-lg font-bold text-white flex items-center gap-2">
            <Bot className="text-brand-500" /> Personal AI
        </h2>
        {!user?.isPremium && (
            <p className="text-xs text-gray-400 mt-1">
                Plano Gratuito: {userMsgCount}/{MAX_FREE_QUESTIONS} perguntas
            </p>
        )}
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {chatHistory.length === 0 && (
          <div className="text-center mt-10 opacity-50">
            <Bot size={48} className="mx-auto mb-2 text-brand-500" />
            <p className="text-sm">Olá, {user?.name}! Sou seu Personal IA.</p>
            <p className="text-xs mt-1">Pergunte sobre sua dieta, execução de exercícios ou motivação.</p>
          </div>
        )}

        {chatHistory.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                msg.role === 'user' 
                ? 'bg-brand-600 text-white rounded-tr-none' 
                : 'bg-dark-card text-gray-200 border border-gray-700 rounded-tl-none'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}

        {isTyping && (
           <div className="flex justify-start">
             <div className="bg-dark-card border border-gray-700 p-3 rounded-2xl rounded-tl-none flex items-center gap-2">
               <Loader2 size={16} className="animate-spin text-brand-500" />
               <span className="text-xs text-gray-400">Digitando...</span>
             </div>
           </div>
        )}

        {isLimitReached && (
            <div className="flex justify-center my-4">
                <div className="bg-yellow-500/10 border border-yellow-500/30 p-4 rounded-xl max-w-xs text-center">
                    <Lock className="w-6 h-6 text-yellow-500 mx-auto mb-2" />
                    <p className="text-yellow-500 font-bold text-sm mb-1">Limite Atingido</p>
                    <p className="text-gray-300 text-xs mb-3">Você atingiu o limite do plano gratuito.</p>
                    <button 
                        onClick={onOpenPremium}
                        className="bg-yellow-500 text-black text-xs font-bold px-4 py-2 rounded-lg w-full"
                    >
                        Virar Premium
                    </button>
                </div>
            </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-dark-card border-t border-gray-800">
        <div className="flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            disabled={isLimitReached || isTyping}
            placeholder={isLimitReached ? "Limite gratuito atingido" : "Digite sua dúvida..."}
            className="flex-1 bg-dark-bg border border-gray-700 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-brand-500 text-sm disabled:opacity-50"
          />
          <button 
            onClick={handleSend}
            disabled={isLimitReached || !input.trim() || isTyping}
            className="bg-brand-600 hover:bg-brand-700 disabled:bg-gray-700 text-white p-3 rounded-xl transition-colors"
          >
            <Send size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

