    return <Welcome onStart={() => setHasStarted(true)} />;
  }

  // Route: Onboarding
  if (!user && hasStarted) {
    return <Onboarding onComplete={() => setActiveTab('dashboard')} />;
  }

  // Route: Authenticated App
  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && <Dashboard />}
