const MainApp = () => {
  const { user, isLoading } = useApp();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [hasStarted, setHasStarted] = useState(false);

  // Loading Overlay
  if (isLoading) {
    return (
      <div className="h-screen w-full bg-dark-bg flex flex-col items-center justify-center text-brand-500">
        <Loader2 size={48} className="animate-spin mb-4" />
        <p className="text-white font-medium animate-pulse">Criando seu plano personalizado...</p>
      </div>
    );
  }

  // Route: Welcome
  if (!user && !hasStarted) {
    return <Welcome onStart={() => setHasStarted(true)} />;
