import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserProfile, WorkoutPlan, ChatMessage } from "../types";

const apiKey = process.env.API_KEY || '';

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey });

// System instruction base for the persona
const PERSONAL_TRAINER_SYSTEM_INSTRUCTION = `
Você é o 'Evolução Fit AI', um Personal Trainer direto e eficiente.

REGRAS DE COMUNICAÇÃO:
- SUAS RESPOSTAS DEVEM SER MUITO CURTAS. Máximo de 2 a 3 frases.
- Vá direto ao ponto.
- Fale como um amigo no WhatsApp.

PERFIL:
- Especialista em emagrecimento e hipertrofia.
- Fornece planos de treino e sugestões alimentares básicas.
`;

export const generateWorkoutPlan = async (user: UserProfile): Promise<WorkoutPlan> => {
  const modelId = "gemini-3-flash-preview";

  const prompt = `
    Crie um plano completo para:
    Nome: ${user.name}, ${user.age} anos, ${user.weight}kg, ${user.height}cm.
    Objetivo: ${user.goal}.
    Nível: ${user.level}.
    Local: ${user.location}.

    1. Crie um plano de treino semanal detalhado.
    2. Para cada exercício, gere uma 'imageKeyword' simples em inglês (ex: "bench press", "squat") para buscar imagens.
    3. Crie um plano alimentar diário EXEMPLO (Sugestão geral saudável) com Café, Almoço, Jantar e Lanches.
  `;

  const exerciseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      name: { type: Type.STRING },
      sets: { type: Type.INTEGER },
      reps: { type: Type.STRING },
      notes: { type: Type.STRING },
      imageKeyword: { type: Type.STRING, description: "Termo curto em inglês para buscar imagem do exercício" },
    },
    required: ["name", "sets", "reps", "imageKeyword"],
  };

  const daySchema: Schema = {
    type: Type.OBJECT,
    properties: {
      day: { type: Type.STRING },
      focus: { type: Type.STRING },
      exercises: {
        type: Type.ARRAY,
        items: exerciseSchema,
      },
    },
    required: ["day", "focus", "exercises"],
  };

  const mealSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      name: { type: Type.STRING, description: "Ex: Café da Manhã" },
      time: { type: Type.STRING, description: "Ex: 08:00" },
      description: { type: Type.STRING, description: "O que comer" },
    },
    required: ["name", "time", "description"],
  };

  const dietSchema: Schema = {
      type: Type.OBJECT,
      properties: {
          dailyCalories: { type: Type.STRING },
          meals: { type: Type.ARRAY, items: mealSchema }
      },
      required: ["dailyCalories", "meals"]
  };

  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      weeklySummary: { type: Type.STRING },
      schedule: {
        type: Type.ARRAY,
        items: daySchema,
      },
      dietPlan: dietSchema
    },
    required: ["weeklySummary", "schedule", "dietPlan"],
  };

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: PERSONAL_TRAINER_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as WorkoutPlan;
  } catch (error) {
    console.error("Error generating workout:", error);
    throw error;
  }
};

export const chatWithTrainer = async (
  history: ChatMessage[], 
  newMessage: string, 
  user: UserProfile
): Promise<string> => {
  const modelId = "gemini-3-flash-preview";

  const contextPrompt = `
  Contexto: ${user.name}, ${user.goal}, ${user.level}.
  Responda de forma extremamente breve (max 30 palavras).
  `;

  const chat = ai.chats.create({
    model: modelId,
    config: {
      systemInstruction: PERSONAL_TRAINER_SYSTEM_INSTRUCTION + contextPrompt,
    }
  });

  for (const msg of history) {
    if (msg.role === 'user') {
      await chat.sendMessage({ message: msg.text });
    } 
  }

  const response = await chat.sendMessage({ message: newMessage });
  return response.text || "Não entendi. Pode repetir?";
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { UserProfile, WorkoutPlan, ChatMessage } from '../types';

interface AppContextType {
  user: UserProfile | null;
  setUser: (user: UserProfile | null) => void;
  workoutPlan: WorkoutPlan | null;
  setWorkoutPlan: (plan: WorkoutPlan | null) => void;
  chatHistory: ChatMessage[];
  addChatMessage: (message: ChatMessage) => void;
  isLoading: boolean;
  setIsLoading: (loading: boolean) => void;
  completeWorkout: () => void;
  logout: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [workoutPlan, setWorkoutPlan] = useState<WorkoutPlan | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Persist user to local storage for demo purposes
  useEffect(() => {
    const storedUser = localStorage.getItem('evofit_user');
    const storedPlan = localStorage.getItem('evofit_plan');
    if (storedUser) setUser(JSON.parse(storedUser));
    if (storedPlan) setWorkoutPlan(JSON.parse(storedPlan));
  }, []);

  useEffect(() => {
    if (user) localStorage.setItem('evofit_user', JSON.stringify(user));
    else localStorage.removeItem('evofit_user');
  }, [user]);

  useEffect(() => {
    if (workoutPlan) localStorage.setItem('evofit_plan', JSON.stringify(workoutPlan));
    else localStorage.removeItem('evofit_plan');
  }, [workoutPlan]);

  const addChatMessage = (message: ChatMessage) => {
    setChatHistory((prev) => [...prev, message]);
  };

  const completeWorkout = () => {
    if (user) {
        const today = new Date().toISOString().split('T')[0];
        const updatedUser = {
            ...user,
            completedWorkouts: [...(user.completedWorkouts || []), today]
        };
        setUser(updatedUser);
    }
  };

  const logout = () => {
    setUser(null);
    setWorkoutPlan(null);
    setChatHistory([]);
    localStorage.clear();
  };

  return (
    <AppContext.Provider value={{
      user,
      setUser,
      workoutPlan,
      setWorkoutPlan,
      chatHistory,
      addChatMessage,
      isLoading,
      setIsLoading,
      completeWorkout,
      logout
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { UserProfile, UserGoal, UserLevel, TrainingLocation, Gender } from '../types';
import { ArrowRight, ArrowLeft, Ruler, Weight, User as UserIcon } from 'lucide-react';
