  };

  const dietSchema: Schema = {
      type: Type.OBJECT,
      properties: {
          dailyCalories: { type: Type.STRING },
          meals: { type: Type.ARRAY, items: mealSchema }
      },
      required: ["dailyCalories", "meals"]
  };

  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      weeklySummary: { type: Type.STRING },
      schedule: {
        type: Type.ARRAY,
        items: daySchema,
      },
      dietPlan: dietSchema
    },
    required: ["weeklySummary", "schedule", "dietPlan"],
  };

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: PERSONAL_TRAINER_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as WorkoutPlan;
  } catch (error) {
    console.error("Error generating workout:", error);
    throw error;
  }
};

export const chatWithTrainer = async (
  history: ChatMessage[], 
  newMessage: string, 
  user: UserProfile
): Promise<string> => {
  const modelId = "gemini-3-flash-preview";

  const contextPrompt = `
  Contexto: ${user.name}, ${user.goal}, ${user.level}.
  Responda de forma extremamente breve (max 30 palavras).
  `;

  const chat = ai.chats.create({
    model: modelId,
    config: {
      systemInstruction: PERSONAL_TRAINER_SYSTEM_INSTRUCTION + contextPrompt,
    }
  });

  for (const msg of history) {
    if (msg.role === 'user') {
      await chat.sendMessage({ message: msg.text });
    } 
  }

  const response = await chat.sendMessage({ message: newMessage });
  return response.text || "Não entendi. Pode repetir?";
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { UserProfile, WorkoutPlan, ChatMessage } from '../types';

interface AppContextType {
  user: UserProfile | null;
  setUser: (user: UserProfile | null) => void;
  workoutPlan: WorkoutPlan | null;
  setWorkoutPlan: (plan: WorkoutPlan | null) => void;
  chatHistory: ChatMessage[];
  addChatMessage: (message: ChatMessage) => void;
  isLoading: boolean;
  setIsLoading: (loading: boolean) => void;
  completeWorkout: () => void;
  logout: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [workoutPlan, setWorkoutPlan] = useState<WorkoutPlan | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Persist user to local storage for demo purposes
  useEffect(() => {
    const storedUser = localStorage.getItem('evofit_user');
    const storedPlan = localStorage.getItem('evofit_plan');
    if (storedUser) setUser(JSON.parse(storedUser));
    if (storedPlan) setWorkoutPlan(JSON.parse(storedPlan));
  }, []);

  useEffect(() => {
    if (user) localStorage.setItem('evofit_user', JSON.stringify(user));
    else localStorage.removeItem('evofit_user');
  }, [user]);

  useEffect(() => {
    if (workoutPlan) localStorage.setItem('evofit_plan', JSON.stringify(workoutPlan));
    else localStorage.removeItem('evofit_plan');
  }, [workoutPlan]);

  const addChatMessage = (message: ChatMessage) => {
    setChatHistory((prev) => [...prev, message]);
  };

  const completeWorkout = () => {
    if (user) {
        const today = new Date().toISOString().split('T')[0];
        // Prevent duplicate entries for the same day
        if (!user.completedWorkouts?.includes(today)) {
            const updatedUser = {
                ...user,
                completedWorkouts: [...(user.completedWorkouts || []), today]
            };
            setUser(updatedUser);
        }
    }
  };

  const logout = () => {
    setUser(null);
    setWorkoutPlan(null);
    setChatHistory([]);
    localStorage.clear();
  };

  return (
    <AppContext.Provider value={{
      user,
      setUser,
      workoutPlan,
      setWorkoutPlan,
      chatHistory,
      addChatMessage,
      isLoading,
      setIsLoading,
      completeWorkout,
      logout
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { UserProfile, UserGoal, UserLevel, TrainingLocation, Gender } from '../types';
import { ArrowRight, ArrowLeft, Ruler, Weight, User as UserIcon } from 'lucide-react';
import { generateWorkoutPlan } from '../services/geminiService';

interface OnboardingProps {
  onComplete: () => void;
}

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const { setUser, setWorkoutPlan, setIsLoading } = useApp();
  const [step, setStep] = useState(1);
  const totalSteps = 4;

  const [formData, setFormData] = useState<Partial<UserProfile>>({
    name: '',
    email: '',
    age: 25,
    weight: 70,
    height: 170,
    gender: Gender.Male,
    goal: UserGoal.MuscleGain,
    level: UserLevel.Beginner,
    location: TrainingLocation.Gym,
    isPremium: true,
    freeQuestionsCount: 0,
    joinedDate: new Date().toISOString(),
    completedWorkouts: [] // Start with zero metrics
  });

  const handleChange = (field: keyof UserProfile, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleNext = async () => {
    if (step < totalSteps) {
      setStep(prev => prev + 1);
    } else {
      // Finish
      setIsLoading(true);
      try {
        const fullProfile = formData as UserProfile;
        setUser(fullProfile);

        // Generate initial plan
        const plan = await generateWorkoutPlan(fullProfile);
        setWorkoutPlan(plan);

        onComplete();
      } catch (error) {
        alert("Erro ao gerar treino inicial. Tente novamente.");
        console.error(error);
      } finally {
        setIsLoading(false);
      }
    }
  };

  const handleBack = () => {
    if (step > 1) setStep(prev => prev - 1);
  };

  return (
    <div className="h-screen bg-dark-bg text-white p-6 flex flex-col max-w-md mx-auto">
      {/* Progress Bar */}
      <div className="mb-8 mt-4">
        <div className="flex justify-between text-xs text-dark-muted mb-2">
          <span>Passo {step} de {totalSteps}</span>
          <span>{Math.round((step / totalSteps) * 100)}%</span>
        </div>
        <div className="h-2 bg-dark-card rounded-full overflow-hidden">
          <div 
            className="h-full bg-brand-500 transition-all duration-300"
            style={{ width: `${(step / totalSteps) * 100}%` }}
          ></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto">
        {step === 1 && (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-2xl font-bold">Vamos criar seu perfil</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm text-dark-muted mb-1">Nome</label>
                <input 
                  type="text" 
                  value={formData.name}
                  onChange={(e) => handleChange('name', e.target.value)}
                  className="w-full bg-dark-card border border-gray-700 rounded-lg p-3 text-white focus:border-brand-500 focus:outline-none"
                  placeholder="Seu nome"
                />
              </div>
              <div>
                <label className="block text-sm text-dark-muted mb-1">Email</label>
                <input 
                  type="email" 
                  value={formData.email}
                  onChange={(e) => handleChange('email', e.target.value)}
                  className="w-full bg-dark-card border border-gray-700 rounded-lg p-3 text-white focus:border-brand-500 focus:outline-none"
                  placeholder="seu@email.com"
                />
              </div>
              <div>
                <label className="block text-sm text-dark-muted mb-1">Sexo Biológico</label>
                <div className="grid grid-cols-2 gap-3">
                  {Object.values(Gender).map((g) => (
                    <button
                      key={g}
                      onClick={() => handleChange('gender', g)}
                      className={`p-3 rounded-lg border ${formData.gender === g ? 'bg-brand-500/20 border-brand-500 text-brand-500' : 'bg-dark-card border-gray-700 text-gray-400'}`}
                    >
                      {g}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-2xl font-bold">Suas medidas</h2>
            <div className="space-y-6">
              <div>
                <label className="block text-sm text-dark-muted mb-1">Idade</label>
                <div className="flex items-center bg-dark-card border border-gray-700 rounded-lg px-3">
                  <UserIcon size={20} className="text-gray-500" />
                  <input 
                    type="number" 
                    value={formData.age}
                    onChange={(e) => handleChange('age', Number(e.target.value))}
                    className="w-full bg-transparent p-3 text-white focus:outline-none"
                  />
                  <span className="text-gray-500 text-sm">anos</span>
                </div>
              </div>
              <div>
                <label className="block text-sm text-dark-muted mb-1">Peso</label>
                <div className="flex items-center bg-dark-card border border-gray-700 rounded-lg px-3">
                  <Weight size={20} className="text-gray-500" />
                  <input 
                    type="number" 
                    value={formData.weight}
                    onChange={(e) => handleChange('weight', Number(e.target.value))}
                    className="w-full bg-transparent p-3 text-white focus:outline-none"
                  />
                  <span className="text-gray-500 text-sm">kg</span>
                </div>
              </div>
              <div>
                <label className="block text-sm text-dark-muted mb-1">Altura</label>
                <div className="flex items-center bg-dark-card border border-gray-700 rounded-lg px-3">
                  <Ruler size={20} className="text-gray-500" />
                  <input 
                    type="number" 
                    value={formData.height}
                    onChange={(e) => handleChange('height', Number(e.target.value))}
                    className="w-full bg-transparent p-3 text-white focus:outline-none"
                  />
                  <span className="text-gray-500 text-sm">cm</span>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-2xl font-bold">Seu Objetivo</h2>
            <div className="grid grid-cols-1 gap-3">
