interface DashboardProps {
    onStartWorkout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ onStartWorkout }) => {
  const { user, workoutPlan } = useApp();
  const [showNotificationBtn, setShowNotificationBtn] = useState(false);

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Bom dia';
    if (hour < 18) return 'Boa tarde';
    return 'Boa noite';
  };

  const todayDate = new Date().toISOString().split('T')[0];
  const todayDayName = new Date().toLocaleDateString('pt-BR', { weekday: 'long' });
  const hasTrainedToday = user?.completedWorkouts?.includes(todayDate);

  const todayWorkout = workoutPlan?.schedule.find(d => d.day.toLowerCase().includes(todayDayName.split('-')[0].toLowerCase())) || workoutPlan?.schedule[0];

  // Notification Logic
  useEffect(() => {
    if ('Notification' in window) {
      if (Notification.permission === 'default' && !hasTrainedToday) {
        setShowNotificationBtn(true);
      } else if (Notification.permission === 'granted' && !hasTrainedToday && user) {
        // If granted and hasn't trained, simulate a "smart reminder" coming in shortly
        // In a real app, this would be server-side, but here we simulate the "Push"
        const timer = setTimeout(() => {
            scheduleReminder(user, 100); 
        }, 15000); // Remind after 15 seconds of being on dashboard without training
        return () => clearTimeout(timer);
      }
    }
  }, [user, hasTrainedToday]);

  const handleEnableNotifications = async () => {
    const granted = await requestNotificationPermission();
    if (granted) {
        setShowNotificationBtn(false);
        // Test immediate notification
        if (user) scheduleReminder(user, 2000);
    }
  };

  // Calculate Chart Data based on history
  const last7Days = Array.from({length: 7}, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      return {
          dateStr: d.toISOString().split('T')[0],
          dayName: d.toLocaleDateString('pt-BR', { weekday: 'short' }).slice(0, 3)
      };
  });

  const chartData = last7Days.map(day => ({
      name: day.dayName.charAt(0).toUpperCase() + day.dayName.slice(1),
      count: user?.completedWorkouts?.includes(day.dateStr) ? 1 : 0
  }));

  const totalWorkouts = user?.completedWorkouts?.length || 0;

  // Streak calculation (simplified)
  let currentStreak = 0;
  if (user?.completedWorkouts && user.completedWorkouts.length > 0) {
      if (hasTrainedToday) currentStreak = 1; 
      if (totalWorkouts > 2) currentStreak = totalWorkouts; 
  }

  return (
    <div className="p-4 space-y-6 animate-fadeIn">
      {/* Welcome Header */}
      <div className="flex justify-between items-start">
        <div>
            <h2 className="text-dark-muted text-sm">{getGreeting()},</h2>
            <h1 className="text-2xl font-bold text-white">{user?.name}</h1>
        </div>
        {showNotificationBtn && (
            <button 
                onClick={handleEnableNotifications}
                className="bg-brand-900/40 border border-brand-500/30 text-brand-500 p-2 rounded-full animate-bounce"
                title="Ativar Lembretes de Treino"
            >
                <Bell size={20} />
            </button>
        )}
      </div>

      {/* Notification Banner - If haven't trained today */}
      {!hasTrainedToday && (
          <div className="bg-blue-900/20 border border-blue-500/50 p-4 rounded-xl flex items-start gap-3 animate-pulse">
            <AlertCircle className="text-blue-400 min-w-[20px] mt-0.5" size={20} />
            <div>
                <h3 className="text-blue-200 font-bold text-sm">Hora de treinar!</h3>
                <p className="text-blue-100/70 text-xs mt-1">
                    Você ainda não registrou seu treino hoje. Mantenha a constância para ver resultados!
                </p>
                {showNotificationBtn && (
                    <button 
                        onClick={handleEnableNotifications}
                        className="mt-2 text-xs bg-blue-500/20 hover:bg-blue-500/40 text-blue-200 px-3 py-1.5 rounded-lg transition-colors font-medium border border-blue-500/30"
                    >
                        Ativar Lembretes
                    </button>
                )}
            </div>
          </div>
      )}

      {/* Stats Grid */}
      <div className="grid grid-cols-2 gap-3">
        <div className="bg-dark-card p-4 rounded-xl border border-gray-800">
          <div className="flex items-center gap-2 text-orange-500 mb-2">
            <Flame size={18} />
            <span className="text-xs font-bold">Sequência</span>
          </div>
          <p className="text-2xl font-bold text-white">{currentStreak} <span className="text-sm font-normal text-gray-500">dias</span></p>
        </div>
        <div className="bg-dark-card p-4 rounded-xl border border-gray-800">
          <div className="flex items-center gap-2 text-brand-500 mb-2">
            <Activity size={18} />
            <span className="text-xs font-bold">Total</span>
          </div>
          <p className="text-2xl font-bold text-white">{totalWorkouts} <span className="text-sm font-normal text-gray-500">treinos</span></p>
        </div>
      </div>

      {/* Today's Workout Card */}
      <div className="bg-gradient-to-br from-brand-900 to-brand-950 p-5 rounded-2xl border border-brand-800 relative overflow-hidden shadow-lg shadow-brand-900/20">
        <div className="absolute right-0 top-0 p-4 opacity-10">
            <Calendar size={60} />
        </div>
        <div className="relative z-10">
            <div className="flex justify-between items-start mb-4">
                <div>
                    <h3 className="text-brand-200 text-sm font-medium uppercase tracking-wider">Treino de Hoje</h3>
                    <p className="text-white font-bold text-lg mt-1 capitalize">{todayWorkout?.focus || "Descanso"}</p>
                </div>
                <span className="bg-brand-500/20 text-brand-300 text-xs px-2 py-1 rounded capitalize">{todayWorkout?.day}</span>
