export const generateWorkoutPlan = async (user: UserProfile): Promise<WorkoutPlan> => {
  const modelId = "gemini-3-flash-preview";

  const prompt = `
    Crie um plano completo para:
    Nome: ${user.name}, ${user.age} anos, ${user.weight}kg, ${user.height}cm.
    Objetivo: ${user.goal}.
    Nível: ${user.level}.
