import { UserProfile, WorkoutPlan } from '../types';

// Keys for LocalStorage
const DB_USERS_KEY = 'evofit_db_users';
const DB_PLANS_KEY = 'evofit_db_plans';
const SESSION_KEY = 'evofit_session_user_id';

// Helper to get DB
const getDB = () => {
    const users = JSON.parse(localStorage.getItem(DB_USERS_KEY) || '{}');
    const plans = JSON.parse(localStorage.getItem(DB_PLANS_KEY) || '{}');
    return { users, plans };
};

// Helper to save DB
const saveDB = (users: any, plans: any) => {
    localStorage.setItem(DB_USERS_KEY, JSON.stringify(users));
    localStorage.setItem(DB_PLANS_KEY, JSON.stringify(plans));
};

export const authService = {
    // Register a new user
    register: async (user: UserProfile): Promise<UserProfile> => {
        return new Promise((resolve, reject) => {
            setTimeout(() => {
                const { users, plans } = getDB();

                // Check if email exists
                const emailExists = Object.values(users).some((u: any) => u.email === user.email);
                if (emailExists) {
                    reject(new Error("Este email já está cadastrado."));
                    return;
                }

                // Create User
                const newUser = { ...user, id: crypto.randomUUID() };
                users[newUser.id] = newUser;
                saveDB(users, plans);

                // Set Session
                localStorage.setItem(SESSION_KEY, newUser.id);
                resolve(newUser);
            }, 800); // Simulate network delay
        });
    },

    // Login
    login: async (email: string, password: string): Promise<{ user: UserProfile, plan: WorkoutPlan | null }> => {
        return new Promise((resolve, reject) => {
            setTimeout(() => {
                const { users, plans } = getDB();

                const user = Object.values(users).find((u: any) => u.email === email && u.password === password) as UserProfile | undefined;

                if (!user) {
                    reject(new Error("Email ou senha inválidos."));
                    return;
                }

                // Set Session
                localStorage.setItem(SESSION_KEY, user.id);

                // Get Plan
                const plan = plans[user.id] || null;

                resolve({ user, plan });
            }, 800);
        });
    },

    // Logout
    logout: () => {
        localStorage.removeItem(SESSION_KEY);
    },

    // Check Session (Auto-login)
    checkSession: async (): Promise<{ user: UserProfile, plan: WorkoutPlan | null } | null> => {
        const userId = localStorage.getItem(SESSION_KEY);
        if (!userId) return null;

        const { users, plans } = getDB();
        const user = users[userId];
        const plan = plans[userId];

        if (user) {
            return { user, plan };
        }
        return null;
    },

    // Save Workout Plan
    savePlan: async (userId: string, plan: WorkoutPlan) => {
        const { users, plans } = getDB();
        plans[userId] = plan;
        saveDB(users, plans);
    },

    // Update User (e.g. completed workouts)
    updateUser: async (user: UserProfile) => {
        const { users, plans } = getDB();
        if (users[user.id]) {
            users[user.id] = user;
            saveDB(users, plans);
        }
    }
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { UserProfile, WorkoutPlan, ChatMessage } from '../types';
import { authService } from '../services/mockBackend.ts';

interface AppContextType {
  user: UserProfile | null;
  setUser: (user: UserProfile | null) => void;
  workoutPlan: WorkoutPlan | null;
  setWorkoutPlan: (plan: WorkoutPlan | null) => void;
  chatHistory: ChatMessage[];
  addChatMessage: (message: ChatMessage) => void;
  isLoading: boolean;
  setIsLoading: (loading: boolean) => void;
  completeWorkout: () => void;
  logout: () => void;
  login: (email: string, pass: string) => Promise<void>;
  register: (user: UserProfile) => Promise<void>;
  saveGeneratedPlan: (plan: WorkoutPlan) => Promise<void>;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [workoutPlan, setWorkoutPlan] = useState<WorkoutPlan | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(true); // Start loading to check session

  // Check for active session on load
  useEffect(() => {
    const checkAuth = async () => {
        try {
            const data = await authService.checkSession();
            if (data) {
                setUser(data.user);
                setWorkoutPlan(data.plan);
            }
        } catch (e) {
            console.error("Session check failed", e);
        } finally {
            setIsLoading(false);
        }
    };
    checkAuth();
  }, []);

  const login = async (email: string, pass: string) => {
      setIsLoading(true);
      try {
          const data = await authService.login(email, pass);
          setUser(data.user);
          setWorkoutPlan(data.plan);
      } catch (e) {
          throw e;
      } finally {
          setIsLoading(false);
      }
  };

  const register = async (newUser: UserProfile) => {
      setIsLoading(true);
      try {
          const registeredUser = await authService.register(newUser);
          setUser(registeredUser);
      } catch (e) {
          throw e;
      } finally {
          setIsLoading(false);
      }
  };

  const saveGeneratedPlan = async (plan: WorkoutPlan) => {
      if (user) {
          await authService.savePlan(user.id, plan);
          setWorkoutPlan(plan);
      }
  };

  const addChatMessage = (message: ChatMessage) => {
    setChatHistory((prev) => [...prev, message]);
  };

  const completeWorkout = () => {
    if (user) {
        const today = new Date().toISOString().split('T')[0];
        // Prevent duplicate entries for the same day
        if (!user.completedWorkouts?.includes(today)) {
            const updatedUser = {
                ...user,
                completedWorkouts: [...(user.completedWorkouts || []), today]
            };
            setUser(updatedUser);
            // Sync with backend
            authService.updateUser(updatedUser);
        }
    }
  };

  const logout = () => {
    authService.logout();
    setUser(null);
    setWorkoutPlan(null);
    setChatHistory([]);
  };

  return (
    <AppContext.Provider value={{
      user,
      setUser,
      workoutPlan,
      setWorkoutPlan,
      chatHistory,
      addChatMessage,
      isLoading,
      setIsLoading,
      completeWorkout,
      logout,
      login,
      register,
      saveGeneratedPlan
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

