                    </h3>
                    <p className="text-white font-bold text-lg mt-1 capitalize">{todayWorkout?.focus || "Descanso"}</p>
                </div>
                <span className={`${isRestDay ? 'bg-blue-500/20 text-blue-300' : 'bg-brand-500/20 text-brand-300'} text-xs px-2 py-1 rounded capitalize`}>
                    {todayWorkout?.day || currentDayName}
